- for s $\in$ V //initialize
- {
- visited[s] $\leftarrow$ 0; d[s] $\leftarrow \infty$; pred[s] $\leftarrow$ NULL;
- }
- for s $\in$ V
- if (visited[s]==0) BFS(s);

| Symbol | Meaning |
|---|---|
| $Q$ | queue contain all visited vertices |
| visited[v] | mark visit state of vertex v |
| d[v] | distance from to v |
| pred[v] | vertex that is preceding v |

- //Breadth first search starts from vertex s
- visited[s] $\leftarrow$ 1; //visited
- d[s] $\leftarrow$ 0; pred[s] $\leftarrow$ NULL;
- Q $\leftarrow$ $\emptyset$; enqueue(Q,s); //Insert s into Q
- while (Q $\ne$ $\emptyset$)
- {
- u $\leftarrow$ dequeue(Q); //Remove u from Q
- for v $\in$ Adj[u]
- if (visited[v] == 0) //not visited yet
- {
- visited[v] $\leftarrow$ 1; //visited
- d[v] $\leftarrow$ d[u] + 1; pred[v] $\leftarrow$ u;
- enqueue(Q,v) //Insert v into Q
- }
- }
